def subarraysWithKDistinct(nums, k):
    def atMost(k):
        m, l, count = {}, 0, 0
        for r, x in enumerate(nums):
            m[x] = m.get(x, 0) + 1
            while len(m) > k:
                m[nums[l]] -= 1
                if m[nums[l]] == 0: del m[nums[l]]
                l += 1
            count += r - l + 1
        return count
    return atMost(k) - atMost(k-1)

